12. **Luma** - `/packages/luma/src/luma-image-model.ts`
13. **Prodia** - `/packages/prodia/src/prodia-image-model.ts`
14. **XAI** - `/packages/xai/src/xai-image-model.ts`
15. **Gateway** - `/packages/gateway/src/gateway-image-model.ts`

### 7. **Implementation Pattern Summary**

**Minimal Required Structure:**

```typescript
import { ImageModelV3, ImageModelV3CallOptions, SharedV3Warning } from '@ai-sdk/provider';
import { postJsonToApi, combineHeaders, createJsonResponseHandler } from '@ai-sdk/provider-utils';

export class MyImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get provider(): string {
    return 'my-provider';
  }

  constructor(readonly modelId: string, private config: MyConfig) {}

  async doGenerate(options: ImageModelV3CallOptions): Promise<ReturnType<ImageModelV3['doGenerate']>> {
    const warnings: SharedV3Warning[] = [];
    const currentDate = new Date();

    // 1. Validate unsupported features
    if (options.aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'Model does not support aspect ratio',
      });
    }

    // 2. Make API call
    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), options.headers),
      body: {
        prompt: options.prompt,
        num_images: options.n,
        size: options.size,
        // map providerOptions
        ...(options.providerOptions['my-provider'] ?? {}),
      },
      successfulResponseHandler: createJsonResponseHandler(myResponseSchema),
      failedResponseHandler: myErrorHandler,
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    // 3. Return standardized response
    return {
      images: response.images, // base64 or Uint8Array
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        'my-provider': {
          images: response.images.map(img => ({ /* metadata */ })),
        },
      },
    };
  }
}
```

**Key Design Decisions:**
- **No automatic conversion:** Return data as provider returns it (base64 or binary)
- **Feature warnings over errors:** Log unsupported features gracefully
- **Provider options namespace:** Use provider name as key to avoid collisions
- **Metadata pass-through:** Preserve provider-specific data without normalization
- **Parallel call handling:** Done in `generateImage()`, not individual models
- **Task-based routing:** Complex providers (Bedrock) use task discrimination

This architecture is designed for maximum flexibility while maintaining a consistent public API.

