# PixelArt AI Provider — Implementation Plan

## Context

The Vercel AI SDK is a monorepo of provider packages that implement standard interfaces (`ImageModelV3`, `LanguageModelV3`, etc.) defined in `@ai-sdk/provider`. This plan adds a new fictional `@ai-sdk/pixelart` package that implements **image generation only** using the `ImageModelV3` interface. The package follows the patterns established by `@ai-sdk/black-forest-labs`, which is the simplest real image-only provider in the repo.

The PixelArt provider will call `https://api.pixelart.ai/v1` and support three provider-specific settings: `style`, `pixelDensity`, and a standard `size`. No text, embedding, or other model types are supported.

---

## Files to Create

All files live under `packages/pixelart/`. No existing files are modified (except the root `tsconfig.json` requires a reference entry — but since the task says "do NOT modify existing provider packages", and the root tsconfig is not a provider package, it should be updated to register the new package for TypeScript project references).

```
packages/pixelart/
├── src/
│   ├── index.ts                        # Public exports
│   ├── pixelart-provider.ts            # Provider factory + interface
│   ├── pixelart-image-model.ts         # ImageModelV3 implementation
│   ├── pixelart-image-settings.ts      # Model IDs + settings types
│   └── version.ts                      # VERSION constant (build-injected)
├── package.json
├── tsconfig.json
├── tsconfig.build.json
├── tsup.config.ts
├── turbo.json
├── vitest.node.config.js
└── vitest.edge.config.js
```

---

## Step-by-Step Implementation

### Step 1 — `packages/pixelart/src/pixelart-image-settings.ts`

Defines public-facing types for model IDs and the provider-specific image settings.

```typescript
// Known model IDs (open-ended with string & {})
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | (string & {});

// Settings passed via providerOptions.pixelart
export interface PixelArtImageSettings {
  /**
   * Visual style of the generated image.
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * Pixel density (dots per unit). Higher values produce finer pixels.
   */
  pixelDensity?: number;
}
```

---

### Step 2 — `packages/pixelart/src/version.ts`

```typescript
declare const __PACKAGE_VERSION__: string | undefined;
export const VERSION: string =
  typeof __PACKAGE_VERSION__ !== 'undefined'
    ? __PACKAGE_VERSION__
    : '0.0.0-test';
```

---

### Step 3 — `packages/pixelart/src/pixelart-image-model.ts`

Implements `ImageModelV3`. Key design decisions:
- Posts JSON to `POST /images/generate`
- Supports standard `size`, `seed`, `n`; warns on `aspectRatio` and `files`/`mask` (unsupported)
- Provider options (`style`, `pixelDensity`) are parsed via `parseProviderOptions` and a Zod schema
- Returns images as base64 strings
- Error handling via `createJsonErrorResponseHandler` with a simple `{ error: { message } }` schema

```typescript
import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  type FetchFunction,
  type Resolvable,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// Zod schema for provider-specific options
const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      pixelDensity: z.number().positive().optional(),
    }),
  ),
);

// Response schema from the fictional PixelArt API
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      images: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// Error schema
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
  }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: data => data.error.message,
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      files,
      mask,
      providerOptions,
      headers,
      abortSignal,
    } = options;

    const warnings: SharedV3Warning[] = [];
    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // Warn about unsupported standard features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'PixelArt does not support aspectRatio; use size instead.',
      });
    }
    if (files != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'PixelArt does not support image editing (files input).',
      });
    }
    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support inpainting (mask input).',
      });
    }

    // Parse provider-specific options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n: n ?? 1,
      size,
      seed,
      ...(pixelArtOptions?.style && { style: pixelArtOptions.style }),
      ...(pixelArtOptions?.pixelDensity != null && {
        pixel_density: pixelArtOptions.pixelDensity,
      }),
    };

    const combinedHeaders = combineHeaders(
      await resolve(this.config.headers),
      headers,
    );

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combinedHeaders,
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images.map(img => img.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}
```

