export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | (string & {});

/**
 * Provider-specific settings for PixelArt image generation.
 * Pass these via `providerOptions.pixelart` in generateImage calls.
 */
export interface PixelArtImageSettings {
  /**
   * Visual style of the generated image.
   * - 'pixel': Classic pixel art style
   * - 'retro': Retro-inspired pixel art
   * - '8bit': 8-bit video game aesthetic
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * Pixel density (dots per unit). Higher values produce finer pixel grids.
   * Must be a positive number.
   */
  pixelDensity?: number;
}

